import io.grpc.stub.StreamObserver;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileUploadService extends FileUploadGrpc.FileUploadImplBase {

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadResponse> responseObserver) {
        return new StreamObserver<FileChunk>() {
            private Path tempFile = null;
            private long totalBytesReceived = 0;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (tempFile == null) {
                        tempFile = Files.createTempFile("upload", ".tmp");
                    }
                    Files.write(tempFile, chunk.getData().toByteArray(), java.nio.file.StandardOpenOption.APPEND);
                    totalBytesReceived += chunk.getData().size();
                    responseObserver.onNext(UploadResponse.newBuilder()
                            .setSuccess(true)
                            .setMessage(String.format("Received %d bytes of data", totalBytesReceived))
                            .build());
                } catch (IOException e) {
                    responseObserver.onError(e);
                }
            }

            @Override
            public void onError(Throwable t) {
                if (tempFile != null) {
                    try {
                        Files.deleteIfExists(tempFile);
                    } catch (IOException e) {
                        // Ignore
                    }
                }
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                try {
                    Path finalPath = Paths.get("final_" + tempFile.getFileName().toString());
                    Files.move(tempFile, finalPath);
                    responseObserver.onNext(UploadResponse.newBuilder()
                            .setSuccess(true)
                            .setMessage(String.format("File uploaded successfully to %s", finalPath))
                            .build());
                    responseObserver.onCompleted();
                } catch (IOException e) {
                    responseObserver.onError(e);
                }
            }
        };
    }
}